1	const PROCESSING_FEE_G = 5;
2	const BLOCK_SIZE = 3;
3	const BLOCK_PRICE_G = 60;
4	const COMPONENT_UNIT_PRICE_G = 25;
5	
6	const MAIN_ITEM_BASE: Record<string, number> = {
7	  sword: 100,
8	  amulet: 60,
9	  staff: 80,
10	  potion: 40,
11	};
12	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
13	
14	type Item = { type: string; cursed?: boolean };
15	type Scenario = {
16	  steps: Array<{ op: "quote"; items: Item[] }>;
17	};
18	
19	const componentBaseForGroup = (count: number): number =>
20	  count === BLOCK_SIZE ? BLOCK_PRICE_G : count * COMPONENT_UNIT_PRICE_G;
21	
22	const componentBaseTotal = (items: Item[]): number => {
23	  const counts = new Map<string, number>();
24	  for (const item of items) {
25	    if (COMPONENT_TYPES.has(item.type)) {
26	      counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
27	    }
28	  }
29	  return [...counts.values()]
30	    .map(componentBaseForGroup)
31	    .reduce((sum, n) => sum + n, 0);
32	};
33	
34	const mainItemBase = (item: Item): number => MAIN_ITEM_BASE[item.type] ?? 0;
35	
36	const mainItemPremium = (item: Item): number => {
37	  const base = mainItemBase(item);
38	  const curseSurcharge = item.cursed ? base * 0.5 : 0;
39	  return base + curseSurcharge;
40	};
41	
42	const applyFirstInsuranceSurcharge = (policyBase: number): number =>
43	  policyBase / 10;
44	
45	const quotePremium = (items: Item[]): number => {
46	  const mainItems = items.filter((i) => !COMPONENT_TYPES.has(i.type));
47	  const policyBase =
48	    mainItems.map(mainItemBase).reduce((sum, n) => sum + n, 0) +
49	    componentBaseTotal(items);
50	  const itemPremiumsTotal =
51	    mainItems.map(mainItemPremium).reduce((sum, n) => sum + n, 0) +
52	    componentBaseTotal(items);
53	  return Math.ceil(
54	    itemPremiumsTotal + applyFirstInsuranceSurcharge(policyBase) + PROCESSING_FEE_G,
55	  );
56	};
57	
58	export const runScenario = (scenario: unknown): unknown => {
59	  const items = (scenario as Scenario).steps[0].items;
60	  return { results: [{ premium: quotePremium(items) }] };
61	};
